// Change this line to point specifically to your WordPress node name
const raw = $node["Fetch Blog"].json; 

// 1. Strip HTML tags from the content
const cleanContent = raw.content.rendered.replace(/<[^>]*>?/gm, '').trim();

// 2. Clean HTML entities from the title
const cleanTitle = raw.title.rendered.replace(/&#8217;/g, "'").replace(/&#8211;/g, "-");

// 3. Extract the Image URL safely
const imageUrl = raw._embedded?.['wp:featuredmedia']?.[0]?.source_url || "";

return {
  id: raw.id,
  title: cleanTitle,
  content: cleanContent,
  link: raw.link,
  image_url: imageUrl
};

let rawAI = $input.item.json.output || $input.item.json.text || "";

try {
  const cleanJSON = rawAI.replace(/```json/g, '').replace(/```/g, '').trim();
  const parsed = JSON.parse(cleanJSON);

  // CRITICAL: This must match the name "data cleanse" exactly as seen in your Step 2
  const sourceData = $node["data cleanse"].json;

  return {
    subject_line: parsed.subject_line,
    newsletter_body: parsed.newsletter_body,
    linkedin_teaser: parsed.linkedin_teaser,
    image_url: sourceData.image_url || "",
    link: sourceData.link || ""
  };
} catch (error) {
  return {
    error: "Parsing failed",
    ai_raw: rawData
  };
}
